mapper.select:
SELECT
    u.id                                                                        AS USERID,
    u.name                                                                      AS USERNAME,
    COUNT(t.id)                                                                 AS TOTALTASKS,
    SUM(CASE WHEN t.status = 'DONE' THEN 1 ELSE 0 END)                         AS DONETASKS,
    COALESCE(SUM(CASE WHEN t.status = 'DONE' THEN t.kpi_contribution ELSE 0 END), 0) AS KPICONTRIBUTION
FROM users u
INNER JOIN membership m ON u.id = m.user_id AND m.org_id = #{orgId}
LEFT JOIN task t ON t.assignee_id = u.id
    AND CAST(t.updated_at AS DATE) >= #{startDate}
    AND CAST(t.updated_at AS DATE) <= #{endDate}
LEFT JOIN project p ON t.project_id = p.id AND p.org_id = #{orgId}
WHERE m.org_id = #{orgId}
GROUP BY u.id, u.name
ORDER BY DONETASKS DESC, KPICONTRIBUTION DESC
